option.value:
package redis

import (
	"context"
	"fmt"
	"os"
	"strconv"

	goredis "github.com/redis/go-redis/v9"
)

// New initializes and returns a Redis client. It expects the following environment variables:
//   - REDIS_ADDR (required), e.g., "localhost:6379" or "redis:6379"
//   - REDIS_PASSWORD (optional)
//   - REDIS_DB (optional, defaults to 0)
func New() (*goredis.Client, error) {
	addr := os.Getenv("REDIS_ADDR")
	if addr == "" {
		return nil, fmt.Errorf("REDIS_ADDR environment variable not set")
	}

	password := os.Getenv("REDIS_PASSWORD")

	dbIndex := 0
	if v := os.Getenv("REDIS_DB"); v != "" {
		if i, err := strconv.Atoi(v); err == nil {
			dbIndex = i
		}
	}

	client := goredis.NewClient(&goredis.Options{
		Addr:     addr,
		Password: password,
		DB:       dbIndex,
	})

	if err := client.Ping(context.Background()).Err(); err != nil {
		return nil, fmt.Errorf("failed to ping Redis: %w", err)
	}

	return client, nil
}
